## Test that BOLT correctly handles R_PPC64_REL24 relocations.
## R_PPC64_REL24 is generated by the BL (branch and link) instruction
## when calling a local function. BOLT must correctly patch the branch
## offset after moving code to new addresses.
# REQUIRES: system-linux
# RUN: llvm-mc -filetype=obj -triple powerpc64le-unknown-linux-gnu %s -o %t.o
# RUN: ld.lld %t.o -o %t.exe -e _start --emit-relocs
# RUN: llvm-bolt %t.exe -o %t.bolt -lite 2>&1 | FileCheck %s
# RUN: %t.bolt
# CHECK: BOLT-INFO: Target architecture: powerpc64le
# CHECK: BOLT-INFO: enabling relocation mode
        .text
        .abiversion 2
## Function foo - simply returns to caller
        .globl foo
        .type  foo, @function
foo:
        .localentry foo, 1
        blr
        .size foo, .-foo
## Entry point - calls foo via BL generating R_PPC64_REL24
        .globl _start
        .type  _start, @function
_start:
        .localentry _start, 1
        bl      foo             # R_PPC64_REL24 relocation
        nop                     # TOC restore slot (required by ELFv2 ABI)
        li      0, 1            # syscall: exit
        li      3, 0            # exit code 0
        sc                      # invoke syscall
        .size _start, .-_start
